// A debounce function ensures that a function is not called too frequently, delaying its execution until a certain amount of time has passed without it being called again.

```javascript
function debounce(func, wait) {
  let timeout;
  return function(...args) {
    clearTimeout(timeout);
    timeout = setTimeout(() => {
      func.apply(this, args);
    }, wait);
  };
}

// Example usage
const handleSearch = debounce((query) => {
  console.log('Searching for:', query);
  // This is where you would typically make an API call
}, 300);

// Simulating typing in a search box
console.log('Start typing (simulated):');
handleSearch('j');
handleSearch('ja');
handleSearch('jav');
handleSearch('java');
handleSearch('javas');
handleSearch('javasc');
handleSearch('javascr');
handleSearch('javascri');
handleSearch('javascrip');
handleSearch('javascript');

// After 300ms of no more calls to handleSearch, the debounced function will execute
```
